mapper.select:
SELECT l.id, l.site_id, s.title AS site_title, l.user_id, l.ip, l.create_time FROM site_click_log l LEFT JOIN site s ON l.site_id = s.id
AND l.site_id = #{dto.siteId}
ORDER BY l.create_time DESC

SELECT DATE(create_time) AS statDate, COUNT(*) AS count
FROM site_click_log
WHERE create_time >= #{startTime}
  AND create_time < #{endTime}
GROUP BY DATE(create_time)
ORDER BY statDate
